import{_ as t,a,b as o,c as d,d as r,e as p}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"เพิ่ม Dropbox Channel","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/upload/dropbox.md","filePath":"th-TH/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"th-TH/upload/dropbox.md"};function h(b,e,u,m,f,g){return n(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="เพิ่ม-dropbox-channel" tabindex="-1">เพิ่ม Dropbox Channel <a class="header-anchor" href="#เพิ่ม-dropbox-channel" aria-label="Permalink to &quot;เพิ่ม Dropbox Channel&quot;">​</a></h1><h2 id="สิ่งที่ต้องเตรียมก่อน" tabindex="-1">สิ่งที่ต้องเตรียมก่อน <a class="header-anchor" href="#สิ่งที่ต้องเตรียมก่อน" aria-label="Permalink to &quot;สิ่งที่ต้องเตรียมก่อน&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>ทำไมต้องใช้</th></tr></thead><tbody><tr><td>Dropbox account</td><td>ใช้ sign in และ authorize app</td></tr><tr><td>Dropbox app</td><td>ใช้ generate <code>App Key</code> และ <code>App Secret</code></td></tr><tr><td>ImgBed domain ของคุณ</td><td>ใช้เป็น OAuth redirect URI</td></tr><tr><td>Available Dropbox storage</td><td>ใช้เป็นพื้นที่เก็บ file จริง</td></tr></tbody></table><h2 id="ขั้นตอนตั้งค่า" tabindex="-1">ขั้นตอนตั้งค่า <a class="header-anchor" href="#ขั้นตอนตั้งค่า" aria-label="Permalink to &quot;ขั้นตอนตั้งค่า&quot;">​</a></h2><h3 id="step-1-สร้าง-dropbox-app" tabindex="-1">Step 1: สร้าง Dropbox App <a class="header-anchor" href="#step-1-สร้าง-dropbox-app" aria-label="Permalink to &quot;Step 1: สร้าง Dropbox App&quot;">​</a></h3><ol><li>เปิด Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>สร้าง app ใหม่</li><li>สำหรับ access type ให้เลือก:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>ตั้งชื่อ app ให้จำง่าย เช่น <code>imgbed-app</code></li><li>เปิด app details page หลังสร้างเสร็จ</li></ol><p>Recommended access type:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Recommended ตรงกับวิธีที่ ImgBed store files</td></tr><tr><td><code>Full Dropbox</code></td><td>ไม่แนะนำ ImgBed ไม่จำเป็นต้อง access ทั้ง account</td></tr></tbody></table><p><img src="'+t+'" alt="Create Dropbox app" loading="lazy"></p><h3 id="step-2-เพิ่ม-redirect-uri" tabindex="-1">Step 2: เพิ่ม Redirect URI <a class="header-anchor" href="#step-2-เพิ่ม-redirect-uri" aria-label="Permalink to &quot;Step 2: เพิ่ม Redirect URI&quot;">​</a></h3><p>ใน Dropbox app details page ให้หา OAuth หรือ Redirect URI settings แล้วเพิ่ม:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>ถ้าใช้ admin panel จากหลาย domain ให้เพิ่ม callback URL ที่ตรงกันทุกตัว</p><p><img src="'+a+'" alt="Configure redirect URI" loading="lazy"></p><h3 id="step-3-configure-app-permissions" tabindex="-1">Step 3: Configure App Permissions <a class="header-anchor" href="#step-3-configure-app-permissions" aria-label="Permalink to &quot;Step 3: Configure App Permissions&quot;">​</a></h3><p>เปิด tab <code>Permissions</code> แล้ว enable scopes อย่างน้อยเหล่านี้:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Required</th><th>Purpose</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Required</td><td>อ่าน account และ quota information</td></tr><tr><td><code>files.metadata.read</code></td><td>Required</td><td>อ่าน file และ folder metadata สำหรับ path checks</td></tr><tr><td><code>files.metadata.write</code></td><td>Required</td><td>สร้าง folders และเขียน metadata</td></tr><tr><td><code>files.content.write</code></td><td>Required</td><td>Upload files ถ้าขาด scope นี้จะเกิด <code>required scope &#39;files.content.write&#39;</code></td></tr><tr><td><code>files.content.read</code></td><td>Recommended</td><td>อนุญาต download, preview และ temporary file links</td></tr></tbody></table><p>เลือก scopes แล้วคลิก <code>Submit</code> ด้านล่าง page</p><p><img src="'+o+'" alt="Add permissions" loading="lazy"></p><p>Important:</p><table tabindex="0"><thead><tr><th>Situation</th><th>ควรทำอะไร</th></tr></thead><tbody><tr><td>เปลี่ยน scopes</td><td>Run token authorization flow ใหม่และรับ <code>Refresh Token</code> ใหม่</td></tr><tr><td>ไม่ reauthorize</td><td>Token เก่าจะไม่ได้ permissions ใหม่ ทำให้ uploads ยัง fail ได้</td></tr></tbody></table><h3 id="step-4-copy-app-credentials" tabindex="-1">Step 4: Copy App Credentials <a class="header-anchor" href="#step-4-copy-app-credentials" aria-label="Permalink to &quot;Step 4: Copy App Credentials&quot;">​</a></h3><p>Save ค่าสองตัวนี้จาก Dropbox app page:</p><table tabindex="0"><thead><tr><th>Dropbox Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="step-5-ใส่-dropbox-channel" tabindex="-1">Step 5: ใส่ Dropbox Channel <a class="header-anchor" href="#step-5-ใส่-dropbox-channel" aria-label="Permalink to &quot;Step 5: ใส่ Dropbox Channel&quot;">​</a></h3><p>ใน Upload Settings เลือก <code>Dropbox</code> แล้วกรอก:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>ใส่อะไร</th></tr></thead><tbody><tr><td>Channel name</td><td>ชื่อที่จำง่าย เช่น <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>เว้นว่างไว้ก่อน</td></tr><tr><td>Root directory</td><td>Optional ค่าเริ่มต้นคือ <code>imgbed</code></td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+d+'" alt="Get token" loading="lazy"></p><h3 id="step-6-รับ-refresh-token" tabindex="-1">Step 6: รับ Refresh Token <a class="header-anchor" href="#step-6-รับ-refresh-token" aria-label="Permalink to &quot;Step 6: รับ Refresh Token&quot;">​</a></h3><ol><li>ใน ImgBed คลิก <code>Get Token</code></li><li>Sign in เข้า Dropbox account ที่ต้องการเชื่อมต่อ</li><li>Approve authorization prompt</li><li>Callback page จะแสดง <code>Refresh Token</code></li><li>Copy token นั้น</li><li>กลับไปที่ ImgBed แล้ว paste ใน field <code>Refresh Token</code></li></ol><p><img src="'+r+'" alt="Copy token" loading="lazy"></p><h2 id="วิธีตรวจสอบ" tabindex="-1">วิธีตรวจสอบ <a class="header-anchor" href="#วิธีตรวจสอบ" aria-label="Permalink to &quot;วิธีตรวจสอบ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>Dropbox channel แสดงหลัง save</td></tr><tr><td>Channel switch</td><td>Channel enable ได้</td></tr><tr><td>Token saved</td><td>Detail page แสดงว่า <code>Refresh Token</code> ถูก save แล้ว</td></tr><tr><td>Upload test</td><td>Test image ปรากฏใน Dropbox app folder</td></tr></tbody></table><p>ถ้าเปิด quota limits ให้คลิก quota query หลัง query สำเร็จ channel card จะแสดง used space, total space และ last update time</p><p><img src="'+p+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>ImgBed บอกว่า configuration incomplete</td><td>ตรวจว่า <code>App Key</code>, <code>App Secret</code> และ <code>Refresh Token</code> ถูกกรอกครบ</td></tr><tr><td>Authorization สำเร็จแต่ไม่มี <code>Refresh Token</code></td><td>คลิก <code>Get Token</code> อีกครั้งและตรวจว่าใช้ offline authorization flow</td></tr><tr><td>Upload fail ด้วย <code>required scope &#39;files.content.write&#39;</code></td><td>Enable <code>files.content.write</code>, คลิก <code>Submit</code>, แล้วรับ <code>Refresh Token</code> ใหม่</td></tr><tr><td>Callback fail</td><td>Confirm redirect URI เป็น <code>https://your-domain.com/api/oauth/dropbox/callback</code></td></tr><tr><td>หา files ไม่เจอ</td><td>Confirm ว่า Dropbox app สร้างใน mode <code>App folder</code></td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>เปิด Dropbox App Console</span></span>
<span class="line"><span>-&gt; สร้าง app</span></span>
<span class="line"><span>-&gt; เลือก App folder access</span></span>
<span class="line"><span>-&gt; เพิ่ม https://your-domain.com/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Enable account_info.read / files.metadata.read / files.metadata.write / files.content.write</span></span>
<span class="line"><span>-&gt; Optionally enable files.content.read</span></span>
<span class="line"><span>-&gt; คลิก Submit</span></span>
<span class="line"><span>-&gt; Copy App Key และ App Secret</span></span>
<span class="line"><span>-&gt; ใส่ใน ImgBed</span></span>
<span class="line"><span>-&gt; คลิก Get Token</span></span>
<span class="line"><span>-&gt; Copy Refresh Token จาก callback page</span></span>
<span class="line"><span>-&gt; Paste กลับเข้า ImgBed แล้ว save</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const q=s(c,[["render",h]]);export{y as __pageData,q as default};
